"""
MKT Context Commentary — 2 Chronicles chapters 6–8
Run: python3 scripts/zc-context-2chronicles-6-8.py

Ch 6: Solomon's dedication prayer — ANE and Second Temple context:
      šēm theology (name-dwelling vs. divine transcendence); the temple as heaven's
      earthly interface; seven petition-categories covering the full scope of
      Deuteronomic covenant consequences; the foreigner prayer (vv32-33) as the
      universal-house-of-prayer vision (Isa 56:7).

Ch 7: Divine response — fire from heaven as ANE divine-acceptance sign; the kāḇôd
      filling the temple as the Sinai-theophany mode; the ḥesed refrain as Second
      Temple liturgical formula; 2 Chr 7:14 as the foundational intercessory
      prayer text of Second Temple Judaism.

Ch 8: Administrative period — the Hiram/Huram town-exchange reversal (contrast
      1 Kgs 9:11-13); Israelites as soldiers vs. Canaanite forced labor (the
      Deuteronomic distinction); the three pilgrim festivals as covenant calendar;
      Ophir as the legendary gold source of the ancient world.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON2 = {
  "6": {
    "1": "<p>Solomon&rsquo;s declaration: &ldquo;The LORD has said he would dwell in thick darkness.&rdquo; The &ldquo;thick darkness&rdquo; (<em>ʿărāpel</em>) is the dark storm-cloud of theophany — the divine mode of appearing at Sinai (Exod 20:21; Deut 4:11; 5:22; 1 Kgs 8:12). It contrasts with the cloud by day and fire by night, and with the glory-cloud that will fill the temple in ch 7. In ANE thought, the storm-cloud was the standard vehicle of divine approach: Baal rode the clouds; Marduk&rsquo;s storm was his chariot. Solomon invokes this shared ANE imagery while redirecting it to YHWH as the one who truly dwells in the divine darkness.</p>",
    "2": "<p>&ldquo;I have built you an exalted house — a place for you to dwell in forever.&rdquo; The claim that the king built the deity&rsquo;s house was the standard ANE royal temple-dedication formula (cf. Gudea of Lagash&rsquo;s temple hymns, c. 2100 BCE; Nebuchadnezzar&rsquo;s temple-building inscriptions). The king who builds the god&rsquo;s house receives the god&rsquo;s protection and blessing in return — a reciprocal obligation. Solomon invokes this convention while the Chronicler simultaneously subverts it: this is YHWH&rsquo;s initiative (he chose Jerusalem, he chose David), not primarily Solomon&rsquo;s achievement.</p>",
    "3": "<p>Solomon turns from addressing YHWH to blessing the whole assembly of Israel. The dual address — to God and to the people — mirrors the structure of the Sinai covenant ceremony (Exod 19-24; Deut 29-30) and anticipates the Second Temple practice of covenant-renewal assemblies. The king stands at the interface between the divine and human parties of the covenant, mediating blessing in both directions.</p>",
    "4": "<p>&ldquo;Blessed be the LORD, the God of Israel, who has fulfilled with his hands what he promised with his mouth to my father David.&rdquo; The formula &ldquo;mouth/hands&rdquo; (<em>bĕpîw... bĕyādāyw</em>) — speech and action — is a characteristically Hebrew way of expressing divine faithfulness: YHWH&rsquo;s words and deeds are perfectly aligned. In ANE thought, the gods&rsquo; promises could be revoked or superseded; YHWH&rsquo;s distinctive claim is that his word is as reliable as his action, a fundamental of Israelite covenant theology.</p>",
    "5": "<p>&ldquo;From the day I brought my people out of Egypt, I chose no city to build a house for my name.&rdquo; The historical retrospect — from the Exodus to the temple — frames the temple&rsquo;s construction as the culmination of the whole redemptive narrative. The &ldquo;name theology&rdquo; (<em>lĕšēm YHWH</em>) is a Deuteronomic development: YHWH&rsquo;s name dwells in the chosen place, not his full personal presence. This was theologically significant: it preserved divine transcendence (YHWH is not confined to a building) while maintaining genuine personal accessibility at a specific location. The Deuteronomic name-theology distinguished Israelite temple theology from the common ANE belief that the deity physically inhabited the statue in the temple.</p>",
    "6": "<p>&ldquo;But I chose Jerusalem for my name to dwell there, and I chose David to lead my people Israel.&rdquo; The double election — city and king — is the Chronicler&rsquo;s theological foundation for the temple. Both choices are YHWH&rsquo;s sovereign acts, not human initiatives. In Second Temple Judaism, Jerusalem&rsquo;s election became the basis for an extensive theology of the holy city as the center of the cosmos (the &ldquo;navel of the earth&rdquo; tradition, cf. Ezek 38:12; Jub 8:19) and the eschatological gathering point of the nations (Isa 2:2-4; Mic 4:1-3).</p>",
    "7": "<p>&ldquo;It was in the heart of my father David to build a house for the name of the LORD.&rdquo; David&rsquo;s <em>heart-intention</em> (<em>ʿim lĕḇāḇ Dāwid ʾāḇî</em>) is commended even though the act was not permitted. In ancient Near Eastern legal and religious thought, intention was morally significant: the Mesopotamian wisdom literature recognized that good intentions had theological value even when the deed was impossible. The Chronicler&rsquo;s insistence on David&rsquo;s heart-intention here preserves his honor and explains why his dynasty, not Jeroboam&rsquo;s, retained the Davidic promise.</p>",
    "8": "<p>YHWH&rsquo;s commendation of David&rsquo;s intention: &ldquo;You did well to have it in your heart.&rdquo; This commendation-of-intention formula has parallels in Mesopotamian royal inscriptions where the deity praises the king&rsquo;s pious motivations. In the biblical context, the commendation simultaneously validates David and explains why the temple-building responsibility passed to Solomon rather than implying any failure on David&rsquo;s part — a narrative concern unique to Chronicles (cf. 1 Chr 22:7-10; 28:2-6 for the blood-guilt explanation).</p>",
    "9": "<p>&ldquo;Your son, born from you, is the one who will build it for my name.&rdquo; The divine nomination of Solomon for the temple-building task reflects an ANE convention in which the deity specifically commissions a particular king for a temple project. In Mesopotamian accounts, the god Ninurta or Enlil might appear to the king in a dream specifying the temple&rsquo;s dimensions and the king&rsquo;s role. YHWH&rsquo;s nomination through prophetic oracle (2 Sam 7:12-13; 1 Chr 17:11-12) follows this convention while differing in its relational-covenant frame.</p>",
    "10": "<p>&ldquo;The LORD has kept the promise he made, for I have succeeded my father David and sit on the throne of Israel.&rdquo; The Chronicler presents the Davidic succession as the demonstration of YHWH&rsquo;s covenant faithfulness. The phrase &ldquo;sit on the throne of Israel&rdquo; invokes the dynastic promise of 2 Sam 7:12-16 — the everlasting Davidic dynasty. For the Chronicler writing in the post-exilic period, this promise remains operative even after the destruction of the Jerusalem throne; the Davidic covenant&rsquo;s validity cannot be negated by historical catastrophe.</p>",
    "11": "<p>&ldquo;There I have placed the ark containing the covenant the LORD made with Israel.&rdquo; The ark as &ldquo;the ark of the covenant&rdquo; (<em>ʾărōn bĕrît YHWH</em>) is the covenant&rsquo;s physical housing — the document-box containing the stone tablets. In ANE treaty practice, covenant documents were deposited at the feet of the deity (as witnessed by Hittite suzerain-vassal treaties). The ark served precisely this function: the covenant documents were placed at YHWH&rsquo;s symbolic footstool. This context makes the ark&rsquo;s placement in the temple&rsquo;s inner sanctuary the central act of the whole dedication.</p>",
    "12": "<p>Solomon stood before the altar of the LORD and stretched out his hands. The posture of stretched-out hands (<em>pāraś kappāyw</em>) was the standard ANE and Israelite posture of petition in prayer (cf. Exod 9:29; 1 Kgs 8:22, 38, 54; Ps 88:9; 143:6; Isa 1:15). It is a gesture of openness and supplication — hands empty and upturned before the divine benefactor. The image of the king praying with outstretched hands before the altar is represented in ancient iconography across the Levant and Mesopotamia.</p>",
    "13": "<p>The bronze platform — five cubits square and three cubits high — is unique to Chronicles (not in 1 Kgs 8). Its dimensions roughly correspond to a medium-sized altar (cf. the tabernacle altar: five cubits square, three cubits high, Exod 27:1). Solomon&rsquo;s standing on a platform elevated him above the assembly while keeping him below the altar — architecturally embodying his position as covenant mediator: above the people but under the divine altar. The kneeling posture on the platform is an unusual combination of royal elevation and personal submission.</p>",
    "14": "<p>&ldquo;LORD, God of Israel, there is no God like you in all heaven or earth.&rdquo; The incomparability formula (<em>ʾên kāmôkā</em> — &ldquo;there is none like you&rdquo;) is the standard praise-declaration of Israelite monotheistic theology (cf. Exod 15:11; Deut 3:24; Ps 86:8; Isa 44:6-8). In an ANE context saturated with competing divine claims, this formula is a polemical declaration: the God of Israel is not merely the greatest among gods but categorically unique. The addition &ldquo;in all heaven or earth&rdquo; covers both the divine and cosmic realms that other Near Eastern cultures populated with gods.</p>",
    "15": "<p>&ldquo;You have kept your promise to your servant, my father David.&rdquo; The invocation of the Davidic covenant as the basis for Solomon&rsquo;s own prayer is theologically important: Solomon prays not on his own merit but on the ground of a covenant YHWH made with David. This is the covenantal logic of intercessory prayer throughout the Hebrew Bible: the pray-er appeals to YHWH&rsquo;s own prior commitments rather than to human worthiness (cf. Exod 32:13 — Moses appeals to the Abrahamic promises).</p>",
    "16": "<p>The conditional promise to David&rsquo;s sons: if they &ldquo;are careful to obey my law (<em>yišmĕrû darKām lāleket bĕtôrātî</em>)&rdquo; — walk carefully in my Torah. The phrase &ldquo;walk in my Torah&rdquo; is Deuteronomic covenant-language (Deut 8:6; 10:12-13; 11:22; 28:9). The condition is demanding but not impossible: it asks for sustained covenant attention (<em>šāmar</em> — guard/watch carefully) rather than perfect moral record. In Second Temple Judaism, this conditional promise became the interpretive key for understanding the Babylonian exile: the kings failed to walk in the Torah, so the exile was YHWH&rsquo;s covenant faithfulness, not failure.</p>",
    "17": "<p>&ldquo;Let the promise you made to your servant David stand firm (<em>yĕʾāmen</em>).&rdquo; The verb <em>ʾāman</em> (be firm/reliable/true) is the root of <em>ʾāmēn</em> — the liturgical affirmation of reliability. Solomon is not asking YHWH to create a new promise but to maintain (<em>qûm</em>) and confirm (<em>ʾāman</em>) what was already spoken. This is the Second Temple theology of prayer as covenant invocation: reminding YHWH (in reverence) of his own commitments and asking for their fulfilment.</p>",
    "18": "<p>&ldquo;But will God truly dwell with human beings on the earth? Even the highest heavens cannot contain you.&rdquo; This is the theological climax and most striking verse of the prayer — the king who has just built YHWH&rsquo;s house immediately acknowledges that YHWH cannot be housed. This double-move is the Deuteronomic solution to the temple problem: the <em>name</em> dwells in the temple, but YHWH himself transcends it. Mesopotamian temples were literally understood as the deity&rsquo;s house — the divine statue (the <em>šalmu</em>) was the deity&rsquo;s embodied presence. Solomon&rsquo;s declaration directly repudiates this: YHWH&rsquo;s person transcends any earthly container, though his name remains accessible there.</p>",
    "19": "<p>&ldquo;Yet give attention to your servant&rsquo;s prayer and plea for mercy, LORD my God.&rdquo; The petition formula &ldquo;give attention&rdquo; (<em>pānîtā</em>) combined with &ldquo;plea for mercy&rdquo; (<em>taḥănûnîm</em>) is the vocabulary of Psalms of lament (cf. Ps 6:9; 28:2, 6; 31:22; 86:6). Solomon&rsquo;s prayer imports the Psalms&rsquo; petition-vocabulary into the temple-dedication liturgy, establishing the connection between personal lament and corporate temple prayer that will characterize Second Temple Judaism.</p>",
    "20": "<p>&ldquo;May your eyes remain open toward this house day and night — toward the place where you promised to put your name.&rdquo; The divine open-eye toward the sanctuary is a comfort in distress: the god who watches the temple also sees the prayers offered there. The temple cult of the ancient Near East included daily rituals to ensure the deity&rsquo;s wakeful attention (<em>takultu</em> ceremonies in Assyria). YHWH&rsquo;s eyes are &ldquo;open day and night&rdquo; — he needs no ritual waking, his attention is perpetual. The place &ldquo;where you promised to put your name&rdquo; (<em>ʾăšer ʾāmartā lāśûm šimkā šām</em>) restates the name-theology of v5-6.</p>",
    "21": "<p>&ldquo;From your heavenly dwelling place (<em>mimmĕkôn šiḇtĕkā haššāmāyim</em>), hear and forgive.&rdquo; The phrase <em>mĕkôn šiḇtĕkā</em> (the place of your sitting/dwelling) appears six times in this prayer (vv21, 30, 33, 39; cf. v27: &ldquo;hear in heaven&rdquo;) — it is the liturgical formula for YHWH&rsquo;s heavenly throne room. This bi-level theology — earthly temple + heavenly dwelling — became foundational for Second Temple Judaism&rsquo;s understanding of prayer: the earthly prayer rises to the heavenly throne via the temple&rsquo;s mediation. The heavenly temple tradition was extensively developed in apocalyptic literature (1 Enoch, Testament of Levi, Qumran texts).</p>",
    "22": "<p>The first petition: oath-disputes. When an individual takes an oath before the altar in YHWH&rsquo;s house, the divine judge is invoked to discern truth from falsehood. The background is the ancient practice of ordeals and oaths at sanctuaries: in the absence of witnesses or evidence, the parties submitted to divine adjudication. The tabernacle had a specific ordeal procedure (Num 5:11-31 — the suspected-adultery ordeal). The temple extends this adjudicative function to a wide range of civil disputes.</p>",
    "23": "<p>&ldquo;Judge your servants by condemning the guilty and bringing what they did on their own head, and by vindicating the innocent.&rdquo; The judicial language — condemning the guilty (<em>rāšāʿ rāšāʿ</em>) and vindicating the innocent (<em>ṣaddēq ṣaddîq</em>) — uses cognate-pair constructions that appear in Israelite legal texts (Deut 25:1; 1 Kgs 8:32). The lex talionis principle (&ldquo;bring what they did on their own head&rdquo;) is covenant-law retribution — the guilty bear their own deed&rsquo;s consequences.</p>",
    "24": "<p>The second petition: military defeat due to sin. This follows the Deuteronomic curse-sequence (Deut 28:25, 48-57 — YHWH giving Israel over to enemies as covenant punishment). The condition for restoration is precise: &ldquo;they turn back (<em>šāḇû</em>) and acknowledge your name (<em>wĕhôdû ʾet šĕmĕkā</em>).&rdquo; The acknowledgment-of-the-name is a covenantal act — to invoke YHWH&rsquo;s name is to re-enter the covenant relationship. In Second Temple thought, this petition governed the theology of military defeat: no foreign victory could be final if the covenant people returned to YHWH.</p>",
    "25": "<p>&ldquo;Bring them back to the land you gave them and their ancestors.&rdquo; The land-return formula is the climax of the covenant-restoration sequence. In Second Temple Judaism, this verse (and its parallel in 1 Kgs 8:34) became a key text for the theology of return from exile: the Babylonian exile was the covenant curse of v24, and the return under Cyrus was the covenant restoration of v25. Ezra-Nehemiah presents the post-exilic restoration as YHWH&rsquo;s hearing of exactly this prayer.</p>",
    "26": "<p>The third petition: drought from heaven. The shutting of heaven (<em>šāmayim wĕniʿĕṣar</em> — heaven closes/is restrained) reflects the ANE understanding of weather as divine gift or punishment. In Canaan, the Baal cycle celebrated Baal&rsquo;s victory over Mot as the means by which rain was restored. The Elijah narrative (1 Kgs 17-18) directly polemicizes against Baal by demonstrating that YHWH, not Baal, controls rain. Solomon&rsquo;s prayer claims that prayer toward the temple — not ritual manipulation of Baal — is the means of restoring rain.</p>",
    "27": "<p>&ldquo;Teach them the right way to walk (<em>hôrîtām ʾet haddereḵ haṭṭôḇâ</em>).&rdquo; The petition adds a teaching dimension to the restoration request: drought ends not merely with rainfall but with covenantal re-education. The verb <em>yārâ</em> (teach/instruct — the root of <em>tôrâ</em>) here performs its primary function: YHWH teaches through adversity as well as through scripture. In Second Temple Judaism, the prophets&rsquo; role as teachers of covenant renewal became the interpretive framework for understanding both drought (as YHWH&rsquo;s pedagogy) and restoration (as the fruit of renewed covenant instruction).</p>",
    "28": "<p>The fourth petition introduces the most comprehensive petition category: famine, plague, blight, mildew, locusts, grasshoppers, enemy siege, &ldquo;whatever disaster or disease there is.&rdquo; The list is drawn from the covenant curses of Deuteronomy 28 (blight and mildew: Deut 28:22; locusts: Deut 28:38, 42; siege: Deut 28:52-57; disease: Deut 28:22, 27-28, 35, 58-61). The range of enumerated disasters is deliberately exhaustive — this petition covers everything Deuteronomy 28 threatens.</p>",
    "29": "<p>&ldquo;Whatever prayer or plea any person makes — each knowing their own pain and grief — when they spread their hands toward this house.&rdquo; The individualizing phrase &ldquo;each knowing their own pain and grief&rdquo; (<em>ʾîš negaʿô ûmakʾōḇô</em>) is striking: the temple is not merely a national institution but a place for individual lament. The person who spreads hands toward the temple carries their specific, unrepeatable suffering. This anticipates the development of individual prayer in Second Temple Judaism, where the synagogue became the local equivalent of this gesture toward Jerusalem.</p>",
    "30": "<p>&ldquo;You alone know the human heart.&rdquo; The divine knowledge of the human heart (<em>kî ʾattâ yādaʿtā lĕḇadĕkā ʾet lĕḇaḇ bĕnê hāʾādām</em>) is the theological grounding of this comprehensive petition. YHWH does not require full disclosure in prayer because he already knows more than the pray-er can articulate. This concept — divine cardiognosis (knowledge of the heart) — was developed extensively in Second Temple literature (e.g., Ps 139:1-4; Prov 21:2; Jer 17:10; Sir 42:18-20) and became a key attribute distinguishing YHWH from other deities who needed to be fully informed through ritual.</p>",
    "31": "<p>&ldquo;So that they may respect you and walk in your ways throughout their lives in the land you gave our ancestors.&rdquo; The goal of all the petition-petitions is not mere relief from suffering but covenant formation: answered prayer produces the fear (<em>yirʾâ</em>) and covenant-walking (<em>lāleḵet bĕdĕrākeykā</em>) that is the end of all YHWH&rsquo;s dealings with Israel. In ANE thought, divine mercy was meant to bind the recipient more closely to the deity; in Israelite theology, this binding is covenant-specific: it results in Torah-walking, not mere gratitude.</p>",
    "32": "<p>The fifth petition uniquely concerns the foreigner (<em>hannākrî</em>) — the non-Israelite who comes to pray toward the temple because of YHWH&rsquo;s great name and mighty arm. This is one of the most theologically significant verses in the entire dedication prayer: the temple is designed from the beginning to be a house of prayer for non-Israelites. The background includes the ANE concept of great temples as universally accessible pilgrimage sites — major temples like Esagila in Babylon or the temples at Karnak attracted devotees from across the ancient world. But Solomon&rsquo;s prayer goes further: he asks that YHWH hear the foreigner&rsquo;s prayer as he hears Israel&rsquo;s.</p>",
    "33": "<p>&ldquo;So that all peoples of the earth may know your name and fear you, as your own people Israel do.&rdquo; The universalistic purpose clause — that the nations might know YHWH — becomes a major prophetic theme (Isa 56:7: &ldquo;my house shall be called a house of prayer for all peoples&rdquo;; Jer 16:19-21; Zech 8:20-23). The Chronicler&rsquo;s inclusion of this petition (= 1 Kgs 8:41-43 without significant change) shows that the universalistic temple vision was not a late Second Temple innovation but embedded in the original dedication prayer tradition.</p>",
    "34": "<p>The sixth petition: battle prayer when Israel goes to war. The prayer toward &ldquo;this city you have chosen (<em>hāʿîr habaḥartā bāh</em>) and this house built for your name&rdquo; is the covenant-warrior invocation. In ancient practice, soldiers prayed toward their deity&rsquo;s temple before battle and the deity was expected to &ldquo;go before&rdquo; the army. The Chronicler&rsquo;s theology of holy war (cf. 2 Chr 20:15, 17; 14:11) consistently frames military success as YHWH&rsquo;s act in response to prayer, not strategic skill.</p>",
    "35": "<p>&ldquo;Uphold their cause (<em>wĕʿāśîtā mišpāṭām</em>).&rdquo; The phrase means &ldquo;execute their justice/judgment&rdquo; — acting as their legal advocate in the court of cosmic adjudication. The military petition is framed legally: YHWH is Israel&rsquo;s legal champion in the battle-as-trial. This forensic understanding of warfare — the stronger army wins because the stronger legal case wins — is distinctive to covenantal combat: victory declares YHWH&rsquo;s verdict on behalf of his covenant people.</p>",
    "36": "<p>&ldquo;When they sin against you — for there is no one who never sins (<em>kî ʾên ʾādām ʾăšer lōʾ yeḥĕṭāʾ</em>).&rdquo; The universal-sin premise is Solomon&rsquo;s most explicitly anthropological statement. The seventh petition (exile and return) grounds itself on the universal human condition of sin. This is not merely the observation that people err; it is a formal premise of the prayer&rsquo;s logic: because all sin, exile is always a possibility, and therefore the restoration prayer of vv37-39 is always relevant. In Second Temple Judaism, this verse anchored the doctrine that the Babylonian exile was the inevitable result of the universal human tendency to sin.</p>",
    "37": "<p>&ldquo;If in the land of their captors they have a change of heart (<em>wĕhēšîḇû ʾel lĕḇāḇām</em>) and repent.&rdquo; The idiom &ldquo;return to their heart&rdquo; is unique — literally &ldquo;they caused to return to their heart&rdquo; — indicating an internal, voluntary act of self-recollection. The three-part confession formula: &ldquo;We have sinned (<em>ḥāṭāʾnû</em>); we have done wrong (<em>heʿĕwînû</em>); we have acted wickedly (<em>rāšaʿnû</em>)&rdquo; — is the covenant-restoration confession (cf. Neh 9:33; Dan 9:5, 15 uses nearly identical language in the post-exilic period, demonstrating that this prayer was the template for Second Temple penitential prayers).</p>",
    "38": "<p>&ldquo;If they repent with all their heart and soul in the land of their captivity, and pray toward their land... this city... and this house.&rdquo; The three-directional prayer — toward the land, toward Jerusalem, toward the temple — became the structural basis of Jewish prayer practice in the Diaspora. The orientation toward Jerusalem (qibla in Arabic; <em>mizraḥ</em> — eastward — in Hebrew) became a fixed element of synagogue architecture and prayer practice. Daniel 6:10 explicitly implements this instruction: Daniel prays with windows open toward Jerusalem three times a day.</p>",
    "39": "<p>&ldquo;Hear from your heavenly dwelling place their prayer and their pleas, uphold their cause, and forgive.&rdquo; The petition for the exiles is the most urgent of all seven: it is the condition in which the post-exilic community found itself and for which Solomon&rsquo;s prayer was most immediately relevant. The Chronicler, writing in the post-exilic period, presents Solomon&rsquo;s prayer as the theological framework for understanding and responding to the exile — it was not a failure of the covenant system but the activation of its own self-correction mechanism.</p>",
    "40": "<p>&ldquo;Now, my God, may your eyes be open and your ears attentive to the prayers offered at this place.&rdquo; The summary petition before the closing doxology asks for continued divine attentiveness — open eyes and attentive ears (<em>qĕšuḇôt</em> — alert/taut/on-edge for sound) — that the temple-as-prayer-conduit remain operative. The anthropomorphic language (divine eyes and ears) is standard Psalms petition-vocabulary (Ps 31:2; 34:15-16; 86:1; 130:2) and does not assert that YHWH has literal sensory organs but that his engagement with human prayer is as certain as human perception.</p>",
    "41": "<p>&ldquo;Arise, LORD God, and come to your resting place — you and the ark of your power.&rdquo; The closing petition is drawn from Ps 132:8-10 — itself a psalm about the ark and the Davidic covenant. The ark is called &ldquo;the ark of your power (<em>ʾărōn ʿuzzĕkā</em>)&rdquo; — the vehicle of YHWH&rsquo;s military might. &ldquo;May your priests be clothed with salvation (<em>yilbĕšû yešûʿâ</em>)&rdquo; — the priests in their vestments become embodiments of YHWH&rsquo;s saving action. The word <em>yĕšûʿâ</em> (salvation) is the root of both Joshua (Hoshea + YHWH) and Jesus — the temple, its priests, and its sacrifices all pointed toward the one whose name means &ldquo;YHWH saves.&rdquo;</p>",
    "42": "<p>&ldquo;LORD God, do not reject your anointed one (<em>ʾal tāšēḇ pĕnê mĕšîḥeykā</em>). Remember your steadfast love for your servant David.&rdquo; The final appeal is to the Davidic covenant and the anointed king who stands in David&rsquo;s place. In Second Temple Judaism, the term <em>māšîaḥ</em> (anointed/Messiah) began to bear the weight of the entire Davidic hope — the expected king who would fulfil all that David&rsquo;s line had promised. Solomon&rsquo;s closing petition for &ldquo;your anointed one&rdquo; thus became a messianic prayer, even if its original referent was Solomon himself. The <em>ḥesed</em> (steadfast love) of David is the ground: YHWH&rsquo;s covenant love is the only basis on which either Solomon or the coming Messiah can approach the holy God.</p>"
  },
  "7": {
    "1": "<p>&ldquo;Fire descended from heaven and consumed the burnt offering and the sacrifices.&rdquo; Fire from heaven as the sign of divine acceptance is a recurring pattern in Israel&rsquo;s cult: at the tabernacle&rsquo;s inauguration (Lev 9:24: &ldquo;fire came out from before the LORD and consumed the burnt offering&rdquo;); at Elijah&rsquo;s Mt Carmel altar (1 Kgs 18:38); and here at the temple dedication. In the broader ANE, fire was associated with divine theophanies across cultures — the Akkadian rites described divine fire consuming offerings at major temples. Israel&rsquo;s unique claim is that the fire originates directly from YHWH without ritual manipulation by human priests.</p>",
    "2": "<p>&ldquo;The priests could not enter the LORD&rsquo;s house because the glory of the LORD had filled it.&rdquo; The <em>kāḇôd YHWH</em> (glory of the LORD) filling the temple is the exact parallel of the <em>kāḇôd</em> filling the tabernacle at its completion (Exod 40:34-35: &ldquo;Moses could not enter the tent of meeting because the cloud had settled on it and the glory of the LORD filled the tabernacle&rdquo;). Both events are Sinai-theophanies: the same divine presence that descended on Sinai in fire and cloud now descends on the earthly sanctuary. The inability of priests to enter is the definitive sign of the <em>kāḇôd</em>&rsquo;s overwhelming presence.</p>",
    "3": "<p>&ldquo;He is good; his steadfast love endures forever (<em>kî ṭôḇ kî lĕʿôlām ḥasdô</em>).&rdquo; This is the central liturgical refrain of Second Temple worship, attested in Ps 100:5; 106:1; 107:1; 118:1, 29; 136 (26 repetitions); Ezra 3:11; Jer 33:11. The refrain&rsquo;s use at this moment of theophany underlines its function: it is the community&rsquo;s response to divine self-disclosure. When YHWH reveals himself in fire and glory, the correct human response is not fear alone but this doxological confession. The word <em>ḥesed</em> (steadfast love/covenant loyalty/lovingkindness) condenses the entire covenant relationship into a single term.</p>",
    "4": "<p>The king and all the people offered sacrifices. The communal participation in the sacrifice that follows the theophany embodies the covenant relationship being inaugurated: God descends, the people respond with sacrifice, the relationship is formally established through the exchange of fire and offering. In ANE temple-dedication ceremonies, royal sacrifice and feast were the standard conclusion to the divine acceptance of the building.</p>",
    "5": "<p>Solomon&rsquo;s dedicatory sacrifice: 22,000 oxen and 120,000 sheep. The scale is hyperbolic in the register of ANE royal generosity — Assyrian royal inscriptions frequently boast of dedicatory feasts with thousands of animals (Shalmaneser III&rsquo;s Calah dedication: 47,074 persons feasted for 10 days). The theological purpose of the scale: the temple dedication is the most significant event in Israel&rsquo;s national life, and its sacrifice must be proportionately greater than any individual or even annual offering. The entire nation is being fed by this sacrifice — &ldquo;so the king and all the people dedicated the house of God.&rdquo;</p>",
    "6": "<p>The Levites play the musical instruments made by David with the refrain &ldquo;for his steadfast love endures forever&rdquo; (the <em>ḥesed</em>-refrain of v3). The priests blow the trumpets opposite them. The musical antiphony between Levites and priests — stringed instruments and brass — is the sonic embodiment of the Mosaic-Davidic temple order: each group contributes to the whole. The specific attribution of the instruments to David preserves the dual authority (Mosaic law + Davidic innovation) that legitimizes the Chronicler&rsquo;s temple music program.</p>",
    "7": "<p>Solomon consecrates the middle of the court for burnt offerings because the bronze altar &ldquo;was too small&rdquo; for the scale of the dedicatory sacrifice. This practical detail is historically plausible: the dedicatory sacrifice of v5 (22,000 oxen + 120,000 sheep) would require a much larger sacrificial area than the standard altar. The temporary use of the courtyard also reflects the practice at the tabernacle&rsquo;s inauguration (Lev 9:22-24 — the courtyard was the full cultic space) and at major festivals when the regular altar was insufficient.</p>",
    "8": "<p>&ldquo;Solomon and all Israel with him celebrated the feast for seven days, from Lebo-hamath to the Wadi of Egypt.&rdquo; The feast covers the full extent of the Davidic kingdom — from the northern border at Lebo-hamath to the Egyptian Wadi in the south. This all-Israel formula (cf. 1 Kgs 8:65) signals that the temple dedication transcends regional significance: the whole covenant people, from north to south, is represented. The seven-day feast mirrors the tabernacle&rsquo;s inauguration week and the Feast of Booths (Lev 23:34-36).</p>",
    "9": "<p>The eighth-day closing assembly (<em>ʿaṣeret</em>). The word <em>ʿăṣāret</em> is the technical term for the &ldquo;assembly/solemn conclusion&rdquo; that closes the Feast of Unleavened Bread (Deut 16:8) and the Feast of Booths (Lev 23:36; Num 29:35). The dedication feast (seven days) and the Feast of Booths (seven days) overlap in the Chronicler&rsquo;s account — the temple dedication was apparently simultaneous with the autumn feast, making the eighth-day conclusion both the end of the dedication and the end of Booths. The total was fourteen days of feast (cf. 2 Chr 30:23 for a similar voluntary doubling).</p>",
    "10": "<p>&ldquo;On the twenty-third day of the seventh month Solomon dismissed the people.&rdquo; The seventh month is Tishri — the most sacred month of the Hebrew calendar, containing the Day of Atonement (10 Tishri), the Feast of Booths (15-21 Tishri), and the closing assembly (22 Tishri). The twenty-third day is the day after the closing assembly — the people leave after the full sacred-calendar celebration. &ldquo;Joyful and glad, thankful for the prosperity the LORD had granted to David, to Solomon, and to Israel his people&rdquo; — three generations of covenant blessing are named: David (the covenant-maker), Solomon (the fulfiller), and Israel (the beneficiary).</p>",
    "11": "<p>The summary of Solomon&rsquo;s completed projects: &ldquo;Everything he set his heart to do in the LORD&rsquo;s house and his own house he carried out successfully.&rdquo; The phrase &ldquo;set his heart to do&rdquo; (<em>bĕlibḇô laʿăśôt</em>) echoes the Chronicler&rsquo;s consistent vocabulary of heart-driven covenant action (cf. 2 Chr 1:11 — Solomon asks for wisdom &ldquo;because this was in your heart&rdquo;). Completion (<em>wayyaṣlîaḥ</em> — he prospered/succeeded) is the covenant promise of Josh 1:7-8 fulfilled: obedient seeking produces successful completion.</p>",
    "12": "<p>&ldquo;The LORD appeared to Solomon at night and told him.&rdquo; The divine night appearance (<em>wayyērāʾ YHWH ʾel Šĕlōmōh ballāyĕlâ</em>) mirrors the Gibeon theophany at the beginning of Solomon&rsquo;s reign (2 Chr 1:7; 1 Kgs 3:5). As the reign begins with a divine night encounter and promise, so the temple dedication ends with one — forming a bracket around Solomon&rsquo;s building program. The night setting is significant: in ANE thought, the night was the time of dream-oracles and divine visitations (cf. Job 33:14-16; Num 12:6).</p>",
    "13": "<p>&ldquo;Whenever I close the sky so that there is no rain, or command locusts to consume the land, or send plague.&rdquo; YHWH explicitly claims agency over the disasters that Solomon&rsquo;s prayer petitioned about (6:26-29). The three examples — drought, locusts, plague — correspond to major categories of ANE divine judgment. In Mesopotamian thought, these were sent by various deities acting independently; YHWH&rsquo;s claim is unified divine sovereignty: all these disasters are his to send or withhold, as one God governing the whole created order.</p>",
    "14": "<p>&ldquo;If my people who bear my name will humble themselves (<em>yikkānĕʿû</em>), pray (<em>yitpallĕlû</em>), seek my face (<em>yĕḇaqĕšû pānāy</em>), and turn from their evil ways (<em>wĕyāšûḇû miḏarĕkêhem hārāʿîm</em>), then I will hear from heaven, forgive their sin, and restore their land.&rdquo; This is the most cited verse in Chronicles and one of the most cited in the Hebrew Bible. The four-condition structure (humble, pray, seek, turn) and four-promise structure (hear, forgive, restore) form a covenant renewal formula that became the standard intercessory prayer model in Second Temple Judaism. The phrase &ldquo;who bear my name&rdquo; (<em>ʾăšer niqrāʾ šĕmî ʿălêhem</em>) — &ldquo;over whom my name is called&rdquo; — is the covenant-identity formula (Deut 28:10; Jer 14:9; Amos 9:12). The people are owned by YHWH&rsquo;s name.</p>",
    "15": "<p>&ldquo;Now my eyes will be open and my ears attentive to every prayer made in this place.&rdquo; YHWH&rsquo;s direct answer to Solomon&rsquo;s petition of 6:20, 40 — the language is nearly identical. The divine response is not just acceptance of the temple but the specific activation of the attentive-eyes-and-ears modality: YHWH will be perpetually alert to prayers offered in the temple. In ANE terms, this is the deity accepting the temple as his legitimate cult-center — an act of divine self-commitment more binding than human dedication.</p>",
    "16": "<p>&ldquo;I have now chosen and consecrated this house so that my name may rest here forever. My eyes and my heart will always be here.&rdquo; The divine three-claims structure: YHWH has chosen (<em>bāḥartî</em>), consecrated (<em>qiddaštî</em>), and committed his name, eyes, and heart to the temple permanently. The triple divine commitment means the temple is not merely a human artifact but a divine institution — YHWH&rsquo;s own choice and commitment underlie its existence. The language of divine &ldquo;heart always here&rdquo; (<em>wĕlibbî yihyeh šām kol hayyāmîm</em>) is the most intimate possible divine attachment to a place — the heart, the seat of will and affection.</p>",
    "17": "<p>The conditional covenant to Solomon: &ldquo;If you walk before me as your father David did — following all my commands and keeping my statutes and ordinances.&rdquo; The verb &ldquo;walk before me&rdquo; (<em>lāleḵet lĕpānay</em>) is the patriarchal covenant term — YHWH told Abram to &ldquo;walk before me and be blameless&rdquo; (Gen 17:1). The Davidic covenant is thus grounded in the Abrahamic. The three-part obedience structure — following commands (<em>miṣwōtay</em>), keeping statutes (<em>ḥuqqōtay</em>), and observing ordinances (<em>mišpāṭay</em>) — is the Deuteronomic Torah-compliance formula (Deut 4:1; 5:31; 6:1; 7:11).</p>",
    "18": "<p>&ldquo;Then I will confirm your royal throne (<em>hăqîmōtî ʾet kissēʾ mamlakĕtkā</em>) as I promised your father David: &lsquo;You will always have a man to rule Israel.&rsquo;&rdquo; The confirmation-of-the-throne promise is conditional in this form (unlike 2 Sam 7:16 which appears unconditional). The Chronicler&rsquo;s presentation, consistent with his retribution theology, emphasizes that the Davidic dynasty&rsquo;s continuation depends on the king&rsquo;s obedience. This conditionality is the lens through which the Chronicler interprets the Babylonian exile: the dynasty ended not because YHWH broke his promise but because the kings broke the condition.</p>",
    "19": "<p>&ldquo;But if you turn away (<em>tāšûḇûn</em>) and abandon my decrees and commands.&rdquo; The warning inverts the promise: the same <em>šûḇ</em> (turn/return) that is positive in covenant restoration (7:14; 6:24, 26, 38) is negative in covenant departure. Return to YHWH brings restoration; turning away from YHWH brings judgment. The Chronicler&rsquo;s narrative demonstrates this theorem across the entire monarchy: every king is ultimately assessed by the direction of his turning.</p>",
    "20": "<p>&ldquo;Then I will uproot Israel from my land (<em>wĕnātaštîm mēʿal ʾadmātî</em>) and will reject this house I consecrated for my name.&rdquo; The exile-threat uses <em>nātaš</em> (uproot/pull out) — a gardening metaphor (cf. Jer 1:10; 18:7; 45:4) for violent removal from a cultivated place. The phrase &ldquo;my land&rdquo; (<em>ʾadmātî</em>) is significant: the land belongs to YHWH, not Israel; Israel is a tenant whose tenancy is conditional on covenant faithfulness (cf. Lev 25:23: &ldquo;the land is mine and you are but aliens and sojourners with me&rdquo;). The temple becoming &ldquo;a proverb and a mockery among all nations&rdquo; reverses the purpose of v33 (that all nations might know YHWH&rsquo;s name).</p>",
    "21": "<p>&ldquo;Everyone who passes by this temple, which was so magnificent, will be appalled and ask, &lsquo;Why did the LORD do this?&rsquo;&rdquo; The &ldquo;passerby appalled&rdquo; motif appears extensively in Jeremiah&rsquo;s oracles against Jerusalem (Jer 18:16; 19:8; Lam 2:15: &ldquo;all who pass by clap their hands at you; they hiss and wag their heads&rdquo;). The rhetorical force: the very temple that was meant to declare YHWH&rsquo;s glory to the nations (6:33) becomes the monument to his judgment if the covenant is broken. The magnificence of the destroyed temple will provoke theological inquiry — which is YHWH&rsquo;s intent.</p>",
    "22": "<p>&ldquo;Because they abandoned the LORD, the God of their ancestors who brought them out of Egypt.&rdquo; The answer to the nations&rsquo; question is the entire Deuteronomic covenant theology compressed into one verse: abandonment (<em>ʿāzĕḇû</em>) of YHWH the Exodus-God → embrace of other gods → covenant punishment → destruction. The Exodus-reference grounds the condemnation: Israel was redeemed from the greatest empire of the day by a uniquely powerful act of divine intervention; their abandonment of this God is the most inexplicable possible apostasy.</p>"
  },
  "8": {
    "1": "<p>The twenty-year building program is complete: the LORD&rsquo;s house (seven years, 2 Chr 3:1-7) and Solomon&rsquo;s palace (thirteen years, 1 Kgs 7:1). The Chronicler&rsquo;s summary signals a transition from the building phase to the administrative phase of Solomon&rsquo;s reign. In ANE royal ideology, a king who built the divine house and the royal palace had completed the essential acts of legitimate kingship — establishing the cosmic and civil order simultaneously.</p>",
    "2": "<p>&ldquo;Solomon rebuilt the towns that Huram had given him and settled Israelites in them.&rdquo; This directly contradicts 1 Kgs 9:11-13, which records that Solomon gave twenty towns in Galilee to Hiram/Huram as payment for timber and gold. The Chronicler&rsquo;s reversal — towns flowing from Hiram to Solomon, not the reverse — reflects either a different source tradition, a reversal of the transaction (Hiram found the towns unsatisfactory and gave them back), or the Chronicler&rsquo;s theological tendency to present Solomon&rsquo;s reign without the financial indebtedness to foreign kings that 1 Kings records.</p>",
    "3": "<p>Solomon captures Hamath-zobah. This is not in 1 Kings; it is unique to Chronicles. Hamath-zobah controlled the Orontes Valley in northern Syria — strategically important for controlling trade routes to Mesopotamia and Anatolia. David had campaigned in this region (2 Sam 8:3-8); Solomon extending that control fits the Chronicler&rsquo;s picture of the Solomonic empire as the full realization of the Davidic territorial promise (Deut 11:24; 1 Chr 13:5).</p>",
    "4": "<p>Tadmor (later called Palmyra) was a crucial oasis city on the trade route across the Syrian desert between the Mediterranean and the Euphrates. Its control gave Solomon leverage over the caravan trade between Egypt and Mesopotamia — the primary commercial arteries of the ancient Near East. The store cities in Hamath represent forward infrastructure for controlling northern trade routes. Solomon&rsquo;s commercial empire was as much about controlling trade arteries as about military conquest.</p>",
    "5": "<p>Upper and Lower Beth-horon were fortified as strategic passes. The Beth-horon ridge controls the main ascent from the coastal plain to Jerusalem — the route that Joshua used in the battle against the five Amorite kings (Josh 10:10-11) and that Judah Maccabee would later use against the Seleucids (1 Macc 3:13-24). Solomon&rsquo;s fortification of these passes was as much defensive as it was commercial — controlling the western approach to the capital.</p>",
    "6": "<p>Baalath (location uncertain, possibly in the Shephelah) and the store cities, chariot cities, and cavalry cities represent the administrative infrastructure of the Solomonic state. The mention of Lebanon alongside Jerusalem in the construction summary reflects the palace complex at Jerusalem that included structures built with Lebanese cedar (1 Kgs 7:2-12: the &ldquo;House of the Forest of Lebanon&rdquo;). The Chronicler&rsquo;s enumeration presents Solomon&rsquo;s realm as a fully organized administrative empire.</p>",
    "7": "<p>The non-Israelite peoples remaining in the land — Hittites, Amorites, Perizzites, Hivites, and Jebusites — are the standard list of Canaanite pre-conquest inhabitants (Exod 3:8, 17; 23:23; Deut 7:1). Their continued presence in the land in Solomon&rsquo;s time reflects the incomplete conquest described in Judges 1:27-36 — Israel never fully expelled them. In Second Temple interpretation, the continuation of Canaanite peoples in Solomon&rsquo;s time was a theological anomaly explained by their conversion to resident-alien status rather than extermination.</p>",
    "8": "<p>Their descendants became forced laborers — <em>mas ʿōḇēd</em> (tribute of service/corvée). The corvée system was standard in ANE state-building: Egypt used it for monumental construction; Mesopotamian kings used it for temple and palace building. Israel&rsquo;s Deuteronomic law prohibited enslaving fellow Israelites (Deut 15:12-15) but permitted using Canaanite peoples as laborers — a distinction the Chronicler carefully preserves. The phrase &ldquo;as they still are today&rdquo; (<em>ʿad hayyôm hazzeh</em>) is a formulaic phrase indicating the practice continued to the writer&rsquo;s time.</p>",
    "9": "<p>&ldquo;Solomon did not conscript Israelites as slaves for his work. They served as soldiers, officers, commanders.&rdquo; The distinction between the status of Canaanites (forced laborers) and Israelites (military officers) reflects the Deuteronomic social ethic: Israelites cannot be reduced to slave-status because they are YHWH&rsquo;s redeemed people (Lev 25:42, 55). The Chronicler&rsquo;s careful preservation of this distinction also responds to the criticism embedded in 1 Kgs 11:28 and 12:4-14, where Solomon&rsquo;s forced labor becomes a cause of the kingdom&rsquo;s division — 2 Chronicles limits the conscription to non-Israelites.</p>",
    "10": "<p>Two hundred and fifty chief officers (<em>śārîm hayyĕṣîḇîm</em> — officers who were stationed/on duty) supervised the workers. The parallel in 1 Kgs 9:23 gives 550 officers rather than 250. The discrepancy has been explained as either a scribal error or a different census that excluded some category of officers. The Chronicler&rsquo;s figure of 250 combined with the 3,600 lower-level supervisors mentioned in 2 Chr 2:2 gives a different total supervisory structure than 1 Kings.</p>",
    "11": "<p>Solomon moves Pharaoh&rsquo;s daughter from the city of David to her own palace because &ldquo;the places where the LORD&rsquo;s ark has been are holy.&rdquo; This theological explanation — not in 1 Kgs 9:24 — reveals a developed concept of holiness-transfer through proximity to the ark. The city of David was sanctified by the ark&rsquo;s temporary residence there (2 Sam 6:12-15; 1 Chr 13-16) before its transfer to the temple. A foreign wife living in a sanctified space creates a ritual incompatibility. This reflects Second Temple purity concerns about the boundaries between the holy and the non-holy.</p>",
    "12": "<p>Solomon&rsquo;s regular burnt offerings on the altar he built &ldquo;in front of the portico&rdquo; (<em>lipnê hāʾûlām</em>) — the vestibule that formed the entrance to the temple. The positioning of the altar before the vestibule is consistent with the temple blueprint (2 Chr 3:4; 4:1): the altar stood in the outer court in front of the vestibule entrance. The term &ldquo;altar he had built&rdquo; refers to the great bronze altar of 2 Chr 4:1 (five cubits tall, twenty cubits square) — the central sacrificial installation of the temple court.</p>",
    "13": "<p>&ldquo;Following the daily schedule, and offering according to Moses&rsquo;s command on Sabbaths, new moons, and the three annual festivals: Unleavened Bread, Weeks, and Booths.&rdquo; The three pilgrim festivals (<em>šālôš rĕgālîm</em>) of Deuteronomy 16 are explicitly named. In Second Temple Judaism, these festivals organized the annual pilgrimage calendar: Jerusalem received enormous populations from throughout the Diaspora and Land for Passover/Unleavened Bread (spring), Weeks/Pentecost (early summer), and Booths/Tabernacles (autumn). The Chronicler&rsquo;s note that Solomon observed Moses&rsquo;s prescribed calendar legitimizes the post-exilic temple&rsquo;s continued observance of these festivals as Solomonic precedent.</p>",
    "14": "<p>&ldquo;Following his father David&rsquo;s regulations, he set up the priestly divisions for their duties and the Levites for their ministry.&rdquo; This is the Chronicler&rsquo;s organizational summary: Solomon implements both Mosaic law (v13) and Davidic innovation (v14) as twin foundations of the temple order. The phrase &ldquo;as each day required (<em>liḏĕḇar yôm bĕyômô</em>)&rdquo; — &ldquo;according to the word of the day in its day&rdquo; — captures the rhythm of the regular cult: each day had its specific requirements that must be met by the appropriate personnel.</p>",
    "15": "<p>&ldquo;Neither the priests nor the Levites deviated from the king&rsquo;s commands in any matter.&rdquo; The full compliance of the religious establishment with Solomon&rsquo;s organization is the Chronicler&rsquo;s ideal: king and cult personnel in perfect alignment. In Second Temple reality, there were ongoing tensions between priestly families, Levitical guilds, and civil authorities over temple administration (cf. Neh 13:10-14; Mal 1:6-2:9). Solomon&rsquo;s temple is presented as the gold standard of institutional harmony that the post-exilic community should aspire to restore.</p>",
    "16": "<p>&ldquo;So all of Solomon&rsquo;s work was carried out from the day the LORD&rsquo;s house was founded to the day it was finished — and the house of the LORD was complete (<em>šālēm</em>).&rdquo; The final word about the temple is <em>šālēm</em> — complete/whole/perfect, the root of Solomon&rsquo;s own name (<em>Šĕlōmōh</em>) and of <em>šālôm</em> (peace). The temple is as complete as the name of the man who built it promised. The Chronicler&rsquo;s literary artistry makes the building&rsquo;s completion echo the builder&rsquo;s name.</p>",
    "17": "<p>Solomon travels to Ezion-geber and Elath on the Red Sea shore in Edom. Ezion-geber (probably Tell el-Kheleifeh near modern Aqaba) was an important port city at the head of the Gulf of Aqaba — the northern arm of the Red Sea. Its strategic value was the access it provided to Red Sea and Indian Ocean trade routes. Control of Edom (established by David, 2 Sam 8:14) gave Solomon access to this maritime terminus.</p>",
    "18": "<p>Huram sends ships and experienced sailors (<em>ʾanšê yōdĕʿê hayyām</em> — men who know the sea). The Phoenician maritime expertise (Tyre was the premier seafaring city of the ancient Mediterranean) is paired with Israelite royal initiative: neither could accomplish the Ophir trade alone. &ldquo;Ophir&rdquo; was legendary in antiquity as a source of fine gold — its location was debated (Arabia, East Africa/Somalia, India have all been proposed). A Tell Qasile ostracon (c. 8th century BCE) mentions &ldquo;gold of Ophir for Beth-horon — 30 shekels,&rdquo; confirming that Ophir gold was a recognized commercial quality-standard. The 450 talents (about 15 metric tons) returned represents an extraordinary commercial return.</p>"
  }
}

def main():
    c = load_comm('mkt-context', '2chronicles')
    merge_comm(c, CHRON2)
    save_comm('mkt-context', '2chronicles', c)
    count = sum(len(v) for v in CHRON2.values())
    print(f'2chronicles mkt-context: wrote {count} verses for ch 6-8')

if __name__ == '__main__':
    main()
